#include <bits/stdc++.h>
using namespace std;
struct city{
    int stu,far;
    string name;
}chose[151];
int main(){
    int many=0,best_choice,best_couse=0;
    while(cin>>chose[many].stu>>chose[many].far>>chose[many].name){
    	best_couse+=chose[many].far*chose[many++].stu;
	}
    best_choice=many-1;
    for(int i=many-2;i>=0;i--){
        int i_couse=0;
        for(int j=0;j<many;j++)
            i_couse+=abs(chose[j].far-chose[i].far)*chose[j].stu;
        if(i_couse<best_couse){
            best_couse=i_couse;
            best_choice=i;
        }
    }
    cout<<chose[best_choice].name<<' '<<best_couse;
    return 0;
}
